INSERT INTO `news` VALUES (2,'provodili-planovye-raboty-po-obnovleniyu','Проводили плановые работы по обновлению','<p>\r\n	Проводили плановые работы по обновлению отопительной системы в наших магазинах. Долго искали, где заказать непосредственно радиаторы, ведь на рынке столько вариантов, а найти подходящий &mdash; огромная проблема.</p>\r\n','2022-03-23 21:27:00',0),(3,'zaklyuchen-ramochnyy-dogovor-na-puskonaladochnye-raboty-s-pao--tatneft-','Заключен рамочный договор на пусконаладочные работы с ПАО «Татнефть»','<p>\r\n	Заключен рамочный договор на пусконаладочные работы с ПАО &laquo;Татнефть&raquo;</p>\r\n','2022-03-24 13:15:00',0),(4,'surst-bkl--v-nastoyaschee-vremya-kompaniya-provodit-puskonaladochnye-raboty-surst-bkl','СУРСТ БКЛ. В настоящее время компания проводит пусконаладочные работы СУРСТ БКЛ ','<p>\r\n	СУРСТ БКЛ. В настоящее время компания проводит пусконаладочные работы СУРСТ БКЛ&nbsp;</p>\r\n','2022-03-24 13:16:00',0),(5,'schit-silovoy-raspredelitelnyy-s-avr','Щит Силовой Распределительный с АВР','<p>\r\n	По опросному листу был спроектирован, собран на собственной площадке, отправлен заказчику и проведены пуско-наладочные работы Щита Силового Распределительного с АВР. Номинальное напряжение 400 В, номинальное напряжение 400 А, два ввода.</p>\r\n','2025-03-24 10:52:00',0),(6,'stroitelno-montajnye-raboty','Строительно-монтажные работы','<p>\r\n	Завершились строительно-монтажные работы по временному переезду операторов двух цехов нефтехимического предприятия. Данный проект предполагал перенос 57-ми APM операторов с прокладкой оптического кабеля, поставкой оборудования, сборкой серверных шкафов, электропитания, перенос ИБП, перенос системы громкоговорящей связи, перенос противопожарной системы, перенос телефонии, монтаж помещений серверных шкафов.</p>\r\n','2025-03-24 10:54:00',0),(7,'puskonaladochnye-raboty','Пусконаладочные работы','<p>\r\n	Закончены пуско-наладочные работы секция блока кристаллизации, склада готового сульфата аммония с узлом отгрузки в автотранспорт ООО &laquo;Нижнекамская ТЭЦ&raquo;, проектов АТХ, АОВ, АПС, АПВ, ГГС, СС, ОС . Проект АТХ выполнен в объеме 940 каналов на базе ПТК &laquo;Прософт-Системы&raquo;, в том числе запущены локальные системы управления блоков комплектных поставок на базе контроллеров &laquo;Siemens&raquo;, &laquo;Schneider Electric&raquo;.</p>\r\n','2025-03-24 10:56:00',0),(8,'moskovskiy-metropoliten','Московский метрополитен','<p>\r\n	В декабре 2024 года завершены работы по разработке конструкторской документации , изготовлению, поставке, строительно - монтажным работам, пусконаладочным работам шкафов системы автоматизации автоматических и электромеханических устройств (АЭМ) и систем управления и работы станций метрополитена (СУРСТ) Станций Новаторска, Университет Дружбы Народов, Ул. Генерала Тюленева, Тютчева, Мамыри, ТПУ Текстильщики - ГУП &laquo;Московский Метрополитен&raquo; г. Москва в количестве 97 штук.</p>\r\n','2025-03-24 11:02:00',0),(9,'stend-asutp','Стенд АСУТП','<p>\r\n	Завершена&nbsp;&nbsp; сборка и наладка стенда АСУТП для кафедры АТПП Казанского Государственного Энергетического Университета</p>\r\n','2025-03-24 11:04:00',0),(10,'puskonaladochnye-raboty-1','Пусконаладочные работы','<p>\r\n	Завершены Пусконаладочные работы на площадке ИНК Иркутский завод полимеров (ИЗП), очистные сооружения ИЗП, Секция биологической очистки промышленных стоков (титул 5300-300). Количество сигналов &ndash; 300 шт.</p>\r\n','2025-03-24 11:05:00',0),(11,'proektirovanie','Проектирование','<p>\r\n	Завершена Разработка разделов проектирования АСУТП, АТХ ОЗХ, АДИС, АИС стадии &laquo;Проектная Документация&raquo; объекта &laquo;Научно-исследовательский центр &quot;R&amp;D Органический синтез&quot;&raquo;. Количество сигналов 600 шт</p>\r\n','2025-03-24 11:07:00',0),(12,'kompleksnaya-avtomatizatsiya','Комплексная автоматизация','<p>\r\n	Завершены работ по проектированию, поставке оборудования и ПО, реализации Scada, по проекту автоматизации системы управления климатической установкой ОАО &laquo;Компании &laquo;Полюс&raquo; на базе шкафов ШУ и ШС. Количество сигналов - 80 шт.</p>\r\n','2025-03-24 11:10:00',0),(13,'sayt-na-rekonstruktsii','Сайт на реконструкции','<p>\r\n	Сайт находится на реконструкции. Следите за навостями на нашем Telegram-канале:</p>\r\n','2025-07-09 08:00:00',1);
