INSERT INTO `pagescats` VALUES (1,'О компании','o-kompanii','<p>\r\n	ООО &laquo;Синтегра&raquo; - компания, успешно работающая на рынке строительства Российской Федерации с 2012 года. Штатная численность предприятия на 2021 год- более 70 человек.</p>\r\n<p>\r\n	Род деятельности - проектирование, поставка оборудования и материалов, осуществление строительно-монтажных, пусконаладочных работ автоматизированных систем, систем связи и систем пожарной сигнализации и противопожарной автоматики на объектах строительства предприятий нефтепереработки, химической и энергетической промышленности, инженерных систем зданий, сооружений.</p>\r\n<p>\r\n	В собственности компании производственные и складские помещения, обеспеченные оборудованием и техникой, необходимыми для производства работ и организации сборочного производства изготовления электрощитового оборудования и шкафов автоматизации.</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	В нашей компании трудятся опытные специалисты по проектированию, монтажу и наладке КИПиА, систем связи и автоматизации, электротехнического оборудования с высоким профессиональным уровнем и ответственностью.</p>\r\n<p>\r\n	На все выполняемые работы имеются лицензии и допуски уполномоченных органов.</p>\r\n',1,'2025-07-08 13:14:50',0),(2,'Сайт на реконструкции','sayt-na-rekonstruktsii','',0,'2025-07-08 13:13:39',1);
/*!40000 ALTER TABLE `pagescats` ENABLE KEYS */;
UNLOCK TABLES;

