INSERT INTO `services` VALUES (11,'cistemy-opovescheniya-i-upravleniya-evakuatsiey',1,'Cистемы оповещения и управления эвакуацией','11_dutoOB_u01.jpg','',1,7,'2025-07-08 12:45:41',0),(12,'avtomatizatsiya-sistem-upravleniya-tehnologicheskimi-protsessami',1,'Автоматизация систем управления технологическими процессами','12_TW6ari_u02.jpg','',1,1,'2025-07-08 12:45:41',0),(13,'sistemy-kontrolya-i-upravleniya-dostupom--ohrany-perimetra',1,'Системы контроля и управления доступом, охраны периметра','13_elqYm0_u03.jpg','<p>\r\n	В современном мире безопасности на объектах различной направленности уделяется особое внимание, вне зависимости от того, крупное это предприятие или небольшой офис, школа или торговый центр. Наряду с традиционным штатом сотрудников охраны, занимающихся выполнением этих функций, используются различные технические системы, расширяющие возможности и функциональность служб охраны &ndash; системы контроля и управления доступом (СКУД).</p>\r\n<p>\r\n	Система контроля и управления доступом &ndash; это элемент системы безопасности, созданный на основе технических устройств и электронных систем управления, объединённых в единую сеть, работающую на специально разработанном программном обеспечении. Кроме этого, система контроля доступа позволяет автоматизировать учёт рабочего времени на предприятии и в офисе, тем самым облегчая работу кадровой службы организации.</p>\r\n<p>\r\n	Автономные СКУД &ndash; это системы, обеспечивающие контроль за отдельным (офисом, магазином и т.д.) или несколькими помещениями, объединёнными общим назначением, когда управление работой осуществляется при помощи отдельного (автономного) контроллера. В таких установках контроллер управления не связан с прочими электронными устройствами управления, а работает автономно. Точкой доступа на контролируемую территорию, как правило, выступает входная дверь. В качестве исполнительного механизма в автономных системах контроля применяется электронный замок или защёлка, а идентификатором &ndash; карта контроля доступа с различными типами считывателей (штриховой, магнитный, проксимити). Автономный контроллер, как правило, работает только &laquo;на вход&raquo; контролируемой территории, а &laquo;на выход&raquo; используются кнопки управления или датчики.</p>\r\n<p>\r\n	Сетевые СКУД &ndash; это системы оснащаются более мощным и функциональным контроллером (или группой контроллеров), обеспечивающим работу СКУД на значительных по площади помещениях, где одновременно может находиться большое количество людей. В таких системах точками доступа служат проходные предприятий или иные сооружения, а в качестве исполнительного механизма используются турникеты или шлюзы. Идентификаторы могут быть различного типа, а сами исполнительные механизмы оснащаются дистанционными считывателями.</p>\r\n<p>\r\n	В качестве дополнительных функций СКУД может быть совмещена с системами видеонаблюдения и охранно-пожарной сигнализации. Также в качестве дополнения могут выступать способы передачи беспроводного сигнала.</p>\r\n',1,14,'2025-07-08 12:45:41',0),(14,'sistemy-gromkogovoryaschego-opovescheniya',1,'Системы громкоговорящего оповещения','14_DUduIA_u04.jpg','<p>\r\n	Системы громкоговорящей связи (ГГС) и громкоговорящего оповещения (ГГО) с давних времён применяются на промышленных объектах, где из-за специфичных условий эксплуатации обычная телефония не подходит, а также, если наличие ГГС регламентируется руководящими документами предприятия. Они используются, например, для быстрой связи диспетчера с персоналом на рабочих местах, предупреждения об авариях, оповещения населения о чрезвычайных ситуациях.</p>\r\n<p>\r\n	В настоящее время для этих целей применяются специализированные решения и переговорные устройства самых разных типов (в том числе всепогодные и взрывозащищенные пульты, IP-телефоны, рабочие места на базе ПК).</p>\r\n<p>\r\n	Традиционно на предприятиях используются цифровые системы громкоговорящей и диспетчерской связи. Они включают в себя центральный узел, который обеспечивает коммутацию сигналов между переговорными устройствами. Этот узел обычно содержит коммутационную матрицу, хотя есть как минимум одно решение, в котором абонентские платы устанавливают соединение между собой самостоятельно. Центральный узел конструктивно выполняется в виде шкафа, содержащего коммутационные процессоры, абонентские комплекты, блок питания и различные вспомогательные устройства. В центральный узел могут включаться как переговорные устройства и другие терминалы системы диспетчерской связи, так и абонентские пункты системы громкого оповещения, также есть решения, где обе системы имеют собственные центральные устройства.</p>\r\n<p>\r\n	Что действительно отличает ГГС от обычной телефонии, так это конструкция терминального оборудования, обусловленная специфическими требованиями среды их применения. Устройства, которые работают в сложных условиях эксплуатации, имеют прочный корпус из металла или усиленного негорючего пластика, обеспечивающий высокую степень защиты от пыли и влаги. Такие устройства зачастую не имеют номеронабирателя и работают в полудуплексном режиме (диспетчер обращается к нужному абоненту напрямую, для ответа нужно нажать и удерживать кнопку на терминале). В местах с высоким уровнем производственного шума используются микрофоны с шумоподавлением и внешние рупорные громкоговорители, такие терминалы используют расширенную полосу частот для передачи голоса. Кроме того, переговорные устройства снабжены оптическим индикатором вызова.</p>\r\n<p>\r\n	Для офисного применения приобрели популярность пульты на основе ПК с сенсорным монитором. На таком дисплее оператор может видеть одновременно порядка сотни абонентов с индикацией их состояния, очередь входящих вызовов и много другой информации.</p>\r\n<p>\r\n	К другому типу терминального оборудования можно отнести громкоговорители оповещения, подключаемые через усилители мощности, сирены аварийной тревоги, видеокамеры, а также датчики тревожной сигнализации. Информация с датчиков может быть выведена на пульт диспетчера, который оперативно оповестит сотрудников и службу экстренного вызова. В аэропортах, железнодорожных и морских вокзалах, станциях метро устанавливаются колонны экстренного вызова, с помощью которых пассажир может обратиться в справочную службу, вызвать сотрудников служб экстренного вызова.</p>\r\n',1,8,'2025-07-08 12:45:41',0),(15,'sistemy-avtomatizatsii-kipia-i-asutp',1,'Системы автоматизации КИПиА и АСУТП','15_u1Zae9_u05.jpg','<p>\r\n	ООО &laquo;Синтегра&raquo; осуществляет комплекс монтажных и пусконаладочных работ систем автоматизации КИПиА и АСУТП, на предприятиях, промышленных и иных объектах. Системы подобного рода представляют собой целый комплекс программных и технических средств, которые обеспечивают регулирование объектов в производственной сфере.</p>\r\n<p>\r\n	Пусконаладочные работы по системам автоматизации, согласно СНиП, осуществляются в три этапа:</p>\r\n<p>\r\n	Первый этап включает: подготовительные работы, изучение рабочей документации, основные характеристики приборов и средств автоматизации.</p>\r\n<p>\r\n	Производится проверка приборов и средств автоматизации с необходимой регулировкой отдельных элементов аппаратуры. При проверке приборов и средств автоматизации проверяют соответствие основных технических характеристик аппаратуры требованиям, установленным в паспортах и инструкциях предприятий-изготовителей.</p>\r\n<p>\r\n	На втором этапе после завершения монтажа систем автоматизации выполняются работы по их автономной наладке.</p>\r\n<p>\r\n	На третьем этапе выполняются работы по комплексной наладке систем автоматизации, доведению параметров настройки приборов и средств автоматизации, каналов связи до значений, при которых системы автоматизации могут быть использованы в эксплуатации.</p>\r\n<p>\r\n	Пусконаладочные работы по системам автоматизации следует проводить в соответствии с требованиями, приведенными в рабочей документации, инструкциях предприятий-изготовителей приборов и средств автоматизации или в отраслевых правилах приемки в эксплуатацию законченных строительством объектов. Проведение монтажных и пусконаладочных работ систем КИПиА и АСУТП завершается приемкой объекта в эксплуатацию.</p>\r\n',1,2,'2025-07-08 12:45:41',0),(16,'sistemy-avtomatizatsii-otopleniya-i-ventilyatsii',1,'Системы автоматизации отопления и вентиляции','16_jhq50Y_u06.jpg','<p>\r\n	Автоматические устройства контроля за работой вентиляционной системы предназначены для поддержания комфортных условий в производственных и жилых помещениях. Если раньше автоматизированные системы отопления и вентиляции встречались преимущественно на объектах с особыми требованиями к условиям внутреннего микроклимата (библиотеки, архивы, склады, музеи, оранжереи и др.), то теперь эти технологии распространяются и на обычные офисные здания, многофункциональные многоэтажки и жилые (как частные, так и многоквартирные) дома, а также производственные объекты различного назначения.</p>\r\n<p>\r\n	Современные системы &ndash; это комплекс автоматического управления микроклиматом помещения. Для поддержки слаженной работы всех механизмов и устройств устанавливается сложная аппаратура с различными датчиками и реле. Только такое обустройство щита автоматики позволяет корректировать действие всей системы вентиляции. Автоматизация систем вентиляции монтируется для решения проблем при использовании вентиляционного оборудования и механизмов.</p>\r\n<p>\r\n	Основные задачи, выполняемые автоматикой вентиляции:</p>\r\n<ul>\r\n	<li>\r\n		решение задач по управлению и мониторингу нормальной работы схемы. Должен устанавливаться сигнализатор аварии, опасных режимах эксплуатации оборудования. Новые разработки позволяют управлять работой схемы удаленно. Оператор наблюдает за функционированием устройства, может вносить коррективы, устанавливать оптимальные режимы.</li>\r\n	<li>\r\n		произведение индивидуального анализа и мониторинга работы каждого отдельного механизма и общей деятельности схемы вентиляции. Датчики устройства доставляют информацию, автоматика производит исследование ситуации и вносит корректировки в работу вентиляционного оборудования. В случае аварии, подается сигнал на кнопку пуска для выключения оборудования.</li>\r\n	<li>\r\n		осуществляет защиту клапанов и водяного контура нагрева от низких температур, не позволяет опускаться температуре до критического уровня.</li>\r\n	<li>\r\n		обеспечивает возможность управления процессом вентилирования помещения, переключая режимы эксплуатации оборудования. При перепадах нагрузки, температуры в помещении &ndash; система управления способна понижать скорость вращения вентиляторов, полностью выключать оборудование и поддерживать комфортные условия в обслуживаемом помещении.</li>\r\n	<li>\r\n		в случае короткого замыкания и других аварийных ситуаций, производит блокировку механизмов, для исключения пожара и поражения людей током.</li>\r\n</ul>\r\n<p>\r\n	Сложность выполняемой работы зависит от укомплектованности щита автоматического устройства. Выпускается ряд типов приборов, устройств и датчиков для создания автоматики управления вентиляцией. Для управления отдельным процессом, предназначены механизмы контроля. Но устройства не только контролируют весь процесс, но и управляют эксплуатацией одного участка схемы. Поэтому, в состав автоматики входят десятки различных реле, датчиков и других приборов. Но данные приборы производят локальное регулирование работы системы или делают замеры. Контроль и определение общего уровня безопасности, всего цикла работы вентиляционной системы, осуществляется с помощью шкафа центрального управления устройства вентиляции.</p>\r\n<p>\r\n	Сложность системы можно понять, ознакомившись с полным списком оборудования данного устройства. Количество определенных датчиков или реле может быть значительным, а некоторые приборы представлены в единственном числе.</p>\r\n',1,9,'2025-07-08 12:45:41',0),(30,'elektromontajnye-raboty',1,'Электромонтажные работы','30_yn4E5p_1617723916_871740.jpg','<p>\r\n	Электромонтажные работы &ndash; это специальный вид строительных работ, выполняемых во время возведения и реконструкции зданий и сооружений разного назначения, которые непременно связаны с профессиональным монтажом электрических сетей. Это воздушные, кабельные линии электропередачи, проводов тока, электрических проводов и т.д., а также различного электрооборудования, к которому относятся электрические машины, распределительные пункты, пульты управления и многое другое.</p>\r\n<p>\r\n	Наша компания предоставляет услуги по проведению электромонтажных работ любой сложности. Все работы производятся в соответствии с ГОСТ, СНиП, ПУЭ.</p>\r\n',1,3,'2025-07-08 12:45:41',0),(31,'avtomatika-protivopojarnyh-meropriyatiy',1,'Автоматика противопожарных мероприятий','31_Gfs34p_2.png','<p>\r\n	По определению, пожар &ndash; это процесс неконтролируемого горения, которое способно нанести значительный материальный ущерб, а также может угрожать здоровью человека. В отдельных случаях распространение неуправляемого огня может привести к разрушительным и смертоносным последствиям. Учитывая тяжелые последствия, к которым может привести пожар, вопросам пожарной безопасности уделяется повышенное внимание на государственном уровне. При этом одним из основных способов, препятствующих возникновению и распространению пожаров, является оснащение объектов специальными техническими средствами, к которым относится система автоматизации пожаротушения.</p>\r\n<p>\r\n	Системы автоматического пожаротушения в общем случае призваны начинать тушение очага возгорания до прибытия пожарных, то есть на ранней стадии его развития. Автоматические установки пожаротушения оснащены специальными ёмкостями, которые заполнены составами, способными эффективно прекратить процесс горения. При этом лучшими считаются комбинированные установки пожаротушения, которые наряду с автоматическим включением допускают и ручной запуск с диспетчерского пульта.</p>\r\n<p>\r\n	Существующие в настоящее время системы автоматического тушения пожара делят на следующие типы:</p>\r\n<ul>\r\n	<li>\r\n		водяные установки;</li>\r\n	<li>\r\n		агрегаты тушения пожара пеной;</li>\r\n	<li>\r\n		системы порошкового пожаротушения;</li>\r\n	<li>\r\n		газовые системы пожаротушения.</li>\r\n</ul>\r\n<p>\r\n	Использование систем газового и порошкового пожаротушения усложняется тем, что вещества, используемые при ликвидации возгорания, опасны для здоровья и жизни человека. Поэтому помещение и вход в него должны быть оборудованы специальными звуковыми и визуальными оповещателями, предупреждающими обслуживающий персонал о начале работы системы автоматического пожаротушения. При этом людям должно быть предоставлено время для того, чтобы покинуть помещение.</p>\r\n<p>\r\n	Каждый объект, в котором предполагается установка технических средств автоматизации пожаротушения, по своему уникален и имеет свои отличительные особенности. Поэтому универсального решения по их установке не существует. В каждом конкретном случае тщательно изучаются особенности объекта, и разрабатывается соответствующий проект, предусматривающий все нюансы выбора, установки и монтажа оборудования.</p>\r\n',1,10,'2025-07-08 12:45:41',0),(32,'pojarnaya-signalizatsiya-i-avtomatizatsiya-pojarotusheniya',1,'Пожарная сигнализация и автоматизация пожаротушения','32_vLtQNq_191.jpg','<p>\r\n	По определению, пожар &ndash; это процесс неконтролируемого горения, которое способно нанести значительный материальный ущерб, а также может угрожать здоровью человека. В отдельных случаях распространение неуправляемого огня может привести к разрушительным и смертоносным последствиям. Учитывая тяжелые последствия, к которым может привести пожар, вопросам пожарной безопасности уделяется повышенное внимание на государственном уровне. При этом одним из основных способов, препятствующих возникновению и распространению пожаров, является оснащение объектов специальными техническими средствами, к которым относятся системы пожарной сигнализации и автоматизации пожаротушения.</p>\r\n<p>\r\n	Пожарная сигнализация &ndash; это одна из базовых составляющих любой системы пожарной безопасности. При этом эффективность последней значительно повышается при использовании дополнительных технических средств, к которым относятся такие системы, как оповещение людей о пожаре, дымоудаление, охранная сигнализация, видеонаблюдение, контроль доступа и др.</p>\r\n<p>\r\n	Пожарная сигнализация предназначена для своевременного обнаружения местонахождения возгорания и передачи специально сформированных сигналов на системы пожарного оповещения и автоматического пожаротушения. В общем случае она состоит из извещателей и приёмно-контрольной аппаратуры, с помощью которой осуществляется обработка и регистрация полученных данных, а также формирование команд, включающих периферийные устройства (звуковые и световые извещатели, блок управления внешними устройствами и пр.).</p>\r\n<p>\r\n	Каждый объект, в котором предполагается установка технических средств пожарной сигнализации и пожаротушения, по своему уникален и имеет свои отличительные особенности. Поэтому универсального решения по их установке не существует. В каждом конкретном случае тщательно изучаются особенности объекта, и разрабатывается соответствующий проект, предусматривающий все нюансы выбора, установки и монтажа оборудования.</p>\r\n',1,11,'2025-07-08 12:45:41',0),(33,'sistemy-videonablyudeniya',1,'Системы видеонаблюдения','33_0CV3wn_guvenlik-kamera-sistemleri.jpg','<p>\r\n	Системы видеонаблюдения предназначены для защиты объекта путём мониторинга за его территорией. Позже полученная с видеокамер информация анализируется, обрабатывается и архивируется на цифровом носителе. Подобным образом, система видеонаблюдения не только следит за объектом, но и записывает полученную видеоинформацию, обрабатывает её и хранит.</p>\r\n<p>\r\n	Монтаж видеонаблюдения производится так, чтобы просматривать наиболее важные места объекта, где расположены материальные ценности. Чаще всего видеокамеры устанавливаются так, чтобы на мониторе отображались стоянки автомобилей, полки торговых залов, помещения складов, места массового скопления людей и т. д. Помимо этого видеонаблюдение контролирует места, через которые можно попасть на объект и выйти из него &ndash; проходные, двери, заборы, ворота и другое. На предприятиях и офисах видеонаблюдение может выполнять функцию контроля за перемещаемыми объектами.</p>\r\n<p>\r\n	В определенных случаях монтаж видеонаблюдения производится в производственных помещениях, чтобы иметь возможность контролировать правильность технологического процесса, как в промышленности, так и в сфере услуг. При проектировании системы видеонаблюдения учитываются определенные критерии. Для подбора наиболее подходящих технических средств, нужно предварительно определить, каким требованиям она должна удовлетворять, какие места она должна контролировать, а также какой объём видеоинформации должен быть сохранен. Для получения таких данных необходимо техническое обследование всего охраняемого объекта.</p>\r\n',1,12,'2025-07-08 12:45:41',0),(34,'sistemy-svyazi',1,'Системы связи','34_e5Vm6S_iStock-956392496.jpg','<p>\r\n	В вопросах организации, управления и работы различных технологических процессов важнейшая роль отводится, как к неотъемлемой части, системам и устройствам связи. Это связано с территориальной распределённостью объектов. Также в пределах объекта могут располагаться десятки отделов, складов, помещений и различных структур, которые постоянно взаимодействуют. Организовать надёжную и оперативную связь в подобном месте очень непросто. Успешно удовлетворить требования к взаимосвязи таких объектов могут системы внутренней связи.</p>\r\n<p>\r\n	Система внутренней связи &ndash; совокупность аппаратных и программных средств, которые позволяют реализовать взаимосвязь между персоналом внутри объекта. Центром внутренней телефонной системы на любом объекте является собственная АТС, отличающаяся от стандартных АТС меньшим количеством абонентов и отделением внешней и внутренней сети. Внутренние сети, реализованные с помощью различных технологий широко распространены и применяются в различных видах организаций, например бизнес-центры и торговые предприятия, крупные производства и промышленные объекты, транспортные компании, службы управления, государственные учреждения и другие организации.</p>\r\n<p>\r\n	Системы внутренней телефонной связи являются альтернативой другим способам коммуникации, применяемым на производствах и в других видах организаций. Независимо от рода и специфики деятельности предприятия, внутренняя связь значительно упрощает коммуникацию между персоналом, что делает работу сотрудников более продуктивной и эффективной. Относительно низкая стоимость реализации такой системы также играет в пользу её внедрения.</p>\r\n',1,13,'2025-07-08 12:45:41',0),(35,'sistema-asdu-ems',1,'Система АСДУ ЭМС','35_aYHNhM_588f0e020a69c8561cc32d2f.jpg','<p>\r\n	Автоматизированная система диспетчерского управления (АСДУ) представляет собой совокупность различных средств, включая технические, аппаратные и программные, которые служат для автоматизации слаженной работы оборудования и персонала, а также обеспечивают рациональный контроль с диспетчерских пультов и пунктов.</p>\r\n<p>\r\n	АСДУ имеют ряд существенных преимуществ. Основными достоинствами этих систем можно назвать следующее:</p>\r\n<ul>\r\n	<li>\r\n		обеспечение оперативного контроля над оборудованием и управление процессами;</li>\r\n	<li>\r\n		автоматизация процессов;</li>\r\n	<li>\r\n		хранение, обработка, анализ и передача информации на пульт диспетчера;</li>\r\n	<li>\r\n		осуществление связи между сотрудниками;</li>\r\n	<li>\r\n		информирование и регистрация сигналов об аварийных ситуациях;</li>\r\n	<li>\r\n		документирование и отчётность;</li>\r\n	<li>\r\n		учёт ресурсов;</li>\r\n	<li>\r\n		увеличение надёжности оборудования;</li>\r\n	<li>\r\n		значительное повышение уровня безопасности;</li>\r\n	<li>\r\n		максимальное снижение влияния человеческого фактора;</li>\r\n	<li>\r\n		отслеживание возникновения нештатных ситуаций;</li>\r\n	<li>\r\n		обеспечение своевременной реакции в экстренных случаях;</li>\r\n	<li>\r\n		увеличение продуктивности работы</li>\r\n</ul>\r\n<p>\r\n	Автоматизированная система диспетчерского управления проектируется индивидуально и может контролировать различные инженерные системы, в зависимости от нужд конкретного заказчика, например безопасность и видеонаблюдение, отопление и водоснабжение, электропитание, доступ свежего воздуха, вентиляция, пожарная система, контроль над возникновением и устранением возгораний.</p>\r\n',1,4,'2025-07-08 12:45:41',0),(36,'ohrannaya-signalizatsiya',1,'Охранная сигнализация','36_ehboKG_ohrannye-signalizacii.jpg','<p>\r\n	Охранная сигнализация предназначена для обнаружения проникновения или его попыток на оборудованный ею объект и формирования соответствующих оповещений (формирование звукового и (или) светового сигнала, передача сообщения о тревоге на удаленный монитор). Принцип ее действия заключается в преобразовании извещателями обнаруженного воздействия в электрический сигнал, передачи его на пульт управления, который предназначен для управления устройствами оповещения и передачи информации.</p>\r\n<p>\r\n	Основным требованием к любому охранному оборудованию является обеспечение надежности работы в различных режимах. Немаловажно как точно будет обнаруживаться место нарушения. С этой целью применяется разделение охраняемой территории на максимально мелкие зоны, каждая из которых контролируется отдельно. Идеальным является отслеживание состояния каждого датчика. Это является возможным при использовании адресного построения системы.</p>\r\n<p>\r\n	Следующее требование к охранной сигнализации &mdash; сохранение работоспособности при отключении сетевого электропитания. Для систем, установленных на крупных объектах, энергопотребление всего оборудования может оказаться таким, что подобрать нужные характеристики блока питания окажется затруднительным. В этом случае нужно разделить электропотребляющие устройства на группы, подключив каждую к отдельному источнику напряжения.</p>\r\n<p>\r\n	Ещё одно немаловажное требование &mdash; исключение возможности несанкционированного воздействия на систему с целью ухудшения её характеристик или полного вывода из строя. Применение технических средств с характеристиками, позволяющими предотвратить, минимизировать или заблаговременно обнаружить последствия постороннего вмешательства позволяет значительно повысить надёжность сигнализации.</p>\r\n<p>\r\n	Немаловажное значение имеет также своевременное техническое обслуживание сигнализации с соблюдением всех требований, предъявляемых к его проведению.</p>\r\n',1,15,'2025-07-08 12:45:41',0),(37,'sistema-avtomatizatsii-i-telemehaniki-elektromehanicheskih-ustroystv--aemu-',1,'Система автоматизации и телемеханики электромеханических устройств (АЭМУ)','','',0,6,'2025-07-08 12:45:41',0),(38,'sistema-upravleniya-i-raboty-stantsiy-metropolitena--surst-',1,'Система управления и работы станций метрополитена (СУРСТ)','','<p class=\"FuturisMarkdown-Paragraph\" color:=\"\" margin-bottom:=\"\" margin-top:=\"\" style=\"font-family: \" ys=\"\">\r\n	<span style=\"font-size:12px;\">Система включает в себя технические решения и устройства, которые позволяют с операторского пульта станционного диспетчера осуществлять непрерывный контроль за состоянием пассажиропотоков в зоне автоматических контрольных пунктов, верхней и нижней площадок эскалаторов, пассажирских платформ и распределительного зала станции.</span></p>\r\n<p class=\"FuturisMarkdown-Paragraph\" color:=\"\" margin-bottom:=\"\" margin-top:=\"\" style=\"font-family: \" ys=\"\">\r\n	<span style=\"font-size:12px;\">Некоторые функции системы СУРСТ:</span></p>\r\n<ul class=\"FuturisMarkdown-UnorderedList\" font-size:=\"\" style=\"margin: 0px; padding-left: 5px; color: rgb(51, 51, 51); font-family: \" ys=\"\">\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; margin-top: 8px; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- мониторинг и управление освещением станции, вестибюлей, подплатформенных помещений, технических этажей;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- мониторинг и управление освещением в тоннелях;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- мониторинг и управление архитектурным освещением;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- контроль работы эскалаторов;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- управление установками вентиляции, отопления и водоснабжения;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- мониторинг и управление водоотливными и канализационными установками;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- мониторинг пожарной и охранной сигнализации.</span></li>\r\n</ul>\r\n',0,5,'2025-07-08 12:45:41',0),(39,'sistema-upravleniya-i-raboty-stantsiy-metropolitena--surst--2',1,'Система управления и работы станций метрополитена (СУРСТ)','39_xo2H9G_photo_2025-03-26_09-05-46.png','<p class=\"FuturisMarkdown-Paragraph\" color:=\"\" margin-bottom:=\"\" margin-top:=\"\" style=\"font-family: \" ys=\"\">\r\n	<span style=\"font-size:12px;\">Система включает в себя технические решения и устройства, которые позволяют с операторского пульта станционного диспетчера осуществлять непрерывный контроль за состоянием пассажиропотоков в зоне автоматических контрольных пунктов, верхней и нижней площадок эскалаторов, пассажирских платформ и распределительного зала станции.</span></p>\r\n<p class=\"FuturisMarkdown-Paragraph\" color:=\"\" margin-bottom:=\"\" margin-top:=\"\" style=\"font-family: \" ys=\"\">\r\n	<span style=\"font-size:12px;\">Некоторые функции системы СУРСТ:</span></p>\r\n<ul class=\"FuturisMarkdown-UnorderedList\" font-size:=\"\" style=\"margin: 0px; padding-left: 5px; color: rgb(51, 51, 51); font-family: \" ys=\"\">\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-type: none; margin-top: 8px; padding-left: 7px;\">\r\n		<span style=\"font-size:12px;\">- мониторинг и управление освещением станции, вестибюлей, подплатформенных помещений, технических этажей;&nbsp;</span></li>\r\n	<li class=\"FuturisMarkdown-ListItem\" data-shift=\"0\" data-value=\"\" style=\"font: var(--depot-font-size-text-m-paragraph) var(--depot-font-text); position: relative; margin-bottom: 8px; list-style-ty