INSERT INTO `settings` VALUES (1,'tel','Телефон','text','','+7 (8555) 41 00 01'),(2,'main_email','Основная почта','text','','info@s-nk.su'),(4,'main_title','Основной заголовок','text','','Инжиниринговая компания ООО «СИНТЕГРА» - системный интегратор, специализирующийся на создании систем управления технологическими процессами, автоматизации и диспетчеризации инженерных систем зданий и сооружений, систем связи и видеонаблюдения'),(5,'main_text','Главный текст в шапке','text','','Многолетний опыт реализации проектов различной степени сложности в нефтяной, газовой и химической промышленности, в сфере образования и науки, автомобильной промышленности и транспортной системы, предприятий пассажирского транспорта, включая метрополитен.'),(6,'button_text','Текст на кнопке','text','','Подробнее'),(7,'button_link','Ссылка на кнопке','text','','http://sintegra-nk.ru/pages/sayt-na-rekonstruktsii.html'),(8,'main_count','Кол-во проектов','text','','725'),(9,'about_title','Заголовок О компании','text','','О компании'),(10,'about_text','Текст О компании','textarea','','<p>\r\n	В настоящее время, ООО &laquo;Синтегра&raquo; &ndash; динамично развивающаяся компания, успешно работающая на рынке строительства Российской Федерации с 2012 года.</p>\r\n<p>\r\n	Ставка на высокий профессионализм, квалификацию и опыт сотрудников позволила создать современную инжиниринговую компанию. Команда специалистов разных областей предприятия работает над решением задач как комплексного, так и индивидуального подхода к удовлетворению конечных требований Заказчика, что делает ООО &laquo;Синтегра&raquo; конкурентоспособным предприятием, которое способно предоставить высокий уровень оказываемых услуг.</p>\r\n<p>\r\n	ООО &laquo;Синтегра&raquo; имеет многолетний опыт реализации проектов различной степени сложности в нефтяной, газовой и химической промышленности, в сфере образования и науки, автомобильной промышленности и транспортной системы, предприятий пассажирского транспорта, включая метрополитен. В настоящее время, ООО &laquo;Синтегра&raquo; &ndash; динамично развивающаяся компания, успешно работающая на рынке строительства Российской Федерации с 2012 года.</p>\r\n<p>\r\n	В настоящее время, ООО &laquo;Синтегра&raquo; &ndash; динамично развивающаяся компания, успешно работающая на рынке строительства Российской Федерации с 2012 года.</p>\r\n<p>\r\n	Ставка на высокий профессионализм, квалификацию и опыт сотрудников позволила создать современную инжиниринговую компанию. Команда специалистов разных областей предприятия работает над решением задач как комплексного, так и индивидуального подхода к удовлетворению конечных требований Заказчика, что делает ООО &laquo;Синтегра&raquo; конкурентоспособным предприятием, которое способно предоставить высокий уровень оказываемых услуг.</p>\r\n<p>\r\n	ООО &laquo;Синтегра&raquo; имеет многолетний опыт реализации проектов различной степени сложности в нефтяной, газовой и химической промышленности, в сфере образования и науки, автомобильной промышленности и транспортной системы, предприятий пассажирского транспорта, включая метрополитен.</p>\r\n'),(11,'about_link','Ссылка на страницу О компании','text','','http://sintegra-nk.ru/pages/sayt-na-rekonstruktsii.html'),(12,'news_num','Кол-во новостей на главной','text','','1'),(13,'address','Адрес','text','','РФ, РТ, г. Нижнекамск, БСИ, ул. Заводская 3 В'),(14,'rejim','Режим работы','text','','Пн - Пт: 08:00 - 17:00');
