INSERT INTO `wp_posts` VALUES (7,1,'2019-10-26 16:51:25','2019-10-26 13:51:25','<ul>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/avtomatizaciya-sistem-upravleniya-texnologicheskimi-processami/\">Монтажные и пусконаладочные работы системы оповещения и управления эвакуацией</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/avtomatizaciya-sistem-upravleniya-texnologicheskimi-processami/\">Автоматизация систем управления технологическими процессами</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-sistem-kontrolya-i-upravleniya-dostupom-oxrany-perimetra/\">Монтажные и пусконаладочные работы систем контроля и управления доступом, охраны периметра</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-gromkogovoryashhego-opoveshheniya/\">Монтажные и пусконаладочные работы громкоговорящего оповещения</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-sistem-avtomatizacii-kipia-i-asutp/\">Монтажные и пусконаладочные работы систем автоматизации КИПиА и АСУТП</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-sistemy-avtomatizacii-otopleniya-i-ventilyacii/\">Монтажные и пусконаладочные работы системы автоматизации отопления и вентиляции</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/elektromontazhnye-raboty/\">Электромонтажные работы</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-avtomatiki-protivopozharnyx-meropriyatij/\">Монтажные и пусконаладочные работы автоматики противопожарных мероприятий</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-pozharnoj-signalizacii-i-avtomatizacii-pozharotusheniya/\">Монтажные и пусконаладочные работы пожарной сигнализации и автоматизации пожаротушения</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-sistem-videonablyudeniya/\">Монтажные и пусконаладочные работы систем видеонаблюдения</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-sistem-svyazi/\">Монтажные и пусконаладочные работы систем связи</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-sistem-asdu-ems/\">Монтажные и пусконаладочные работы систем АСДУ ЭМС</a></li>\r\n 	<li><a href=\"http://sintegra-nk.ru/uslugi/montazhnye-i-puskonaladochnye-raboty-oxrannoj-signalizacii/\">Монтажные и пусконаладочные работы охранной сигнализации</a></li>\r\n</ul>','Услуги','','publish','closed','closed','','uslugi','','','2019-10-27 15:22:33','2019-10-27 12:22:33','',0,'http://sintegra-nk.ru/?page_id=7',0,'page','',0),(8,1,'2019-10-26 16:51:25','2019-10-26 13:51:25','','Услуги','','inherit','closed','closed','','7-revision-v1','','','2019-10-26 16:51:25','2019-10-26 13:51:25','',7,'http://sintegra-nk.ru/2019/10/26/7-revision-v1/',0,'revision','',0),(9,1,'2019-10-26 16:52:35','2019-10-26 13:52:35','<table>\r\n<tbody>\r\n<tr>\r\n<td><a href=\"http://sintegra-nk.ru/informaciya/licenzii/\"><img class=\"alignnone size-medium wp-image-108\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/lic_mchs_info-1-213x300.png\" alt=\"\" width=\"213\" height=\"300\" />Лицензии</a></td>\r\n<td><a href=\"http://sintegra-nk.ru/informaciya/vypiski-iz-reestra-sro/\"><img class=\"alignnone size-medium wp-image-110\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_proekt_info-1-212x300.png\" alt=\"\" width=\"212\" height=\"300\" />\r\n\r\nВыписки из реестра СРО</a></td>\r\n</tr>\r\n<tr>\r\n<td><a href=\"http://sintegra-nk.ru/informaciya/sertifikaty/\"><img class=\"alignnone size-medium wp-image-109\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sert_004_info-1-212x300.png\" alt=\"\" width=\"212\" height=\"300\" />Сертификаты</td>\r\n<td><a href=\"http://sintegra-nk.ru/informaciya/uvedomleniya-rostexnadzora/\"><img class=\"alignnone size-medium wp-image-111\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/uved_rtn_info-1-213x300.png\" alt=\"\" width=\"213\" height=\"300\" />\r\n\r\nУведомления Ростехнадзора</a></td>\r\n</tr>\r\n</tbody>\r\n</table>','Информация','','publish','closed','closed','','informaciya','','','2019-10-27 15:54:10','2019-10-27 12:54:10','',0,'http://sintegra-nk.ru/?page_id=9',0,'page','',0),(10,1,'2019-10-26 16:52:35','2019-10-26 13:52:35','','Информация','','inherit','closed','closed','','9-revision-v1','','','2019-10-26 16:52:35','2019-10-26 13:52:35','',9,'http://sintegra-nk.ru/2019/10/26/9-revision-v1/',0,'revision','',0),(11,1,'2019-10-26 16:52:44','2019-10-26 13:52:44','<p style=\"text-align: justify;\">ООО «Синтегра» является динамично развивающейся компанией, успешно работающей на рынке строительства Российской Федерации более семи лет. За время работы фирма уже положительно зарекомендовала себя в глазах многих крупных Заказчиков, среди которых, ГУП «Московский метрополитен», на объектах которого работает более четырёх лет, в ходе которых выполнялись строительно-монтажные и пусконаладочные работы на станциях «Котельники» и «Спартак» Таганско-Краснопресненской линии, станциях «Технопарк», «Ховрино» и «Беломорская» Замоскворецкой линии, станциях «Раменки», «Минская», «Ломоносовский проспект», «Новопеределкино» Калининско-Солнцевской линии, станциях «Хорошевская», «Шелепиха», «Нижняя Масловка» Третьего пересадочного контура, электродепо «Солнцево» и «Руднево» по автоматизированной системе диспетчерского управления электромеханической службы и службы электроснабжения. На сегодняшний день заключены договора и ведутся строительно-монтажные работы по станции «Косино» Кожуховской линии.</p>\r\n<p style=\"text-align: justify;\">К примеру, на станции «Ховрино» нами были выполнены монтажные и пусконаладочные работы по системе АСДУ ЭМС, в основе функционирования которой лежит автоматическое управление объектами ЭМС с помощью локальных систем автоматики, обеспечивающих выполнение заданного режима работы, безопасное протекание технологического процесса, защита оборудования и аварийная сигнализация.</p>\r\n<p style=\"text-align: justify;\">Помимо выполнения монтажных и пусконаладочных работ наша компания произвела поставку шкафов автоматизации на Электродепо «Солнцево», шкафов КПС и щитов питания КПС на станции «Новопеределкино», «Ховрино», «Беломорская». Несмотря на сжатые сроки строительства, вся продукция была отгружена в срок, что немаловажно при строительстве таких крупных объектов как ГУП «Московский Метрополитен». Качество нашей продукции подтверждено Декларацией и Сертификатом соответствия.</p>\r\n<p style=\"text-align: justify;\"><strong>Также наша организация принимала активное участие в строительстве ОАО «ТАНЕКО», а именно:</strong></p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: justify;\">титул 095, «Системы газоанализа и учёта потребления газов»;</li>\r\n 	<li style=\"text-align: justify;\">титул 133, «Контроль и Автоматика, Автоматизация технологических хозяйств и вибромониторинга»;</li>\r\n 	<li style=\"text-align: justify;\">титул 072/1, «Система автоматизации общеобменной Вентиляции»;</li>\r\n 	<li style=\"text-align: justify;\">титул 064, «Промышленное телевидение»;</li>\r\n 	<li style=\"text-align: justify;\">титул 155, «Наружные сети связи, Пожарная сигнализация, Промышленная технологическая связь»;</li>\r\n 	<li style=\"text-align: justify;\">титул 145, 146, «Автоматизация технологических хозяйств»;</li>\r\n 	<li style=\"text-align: justify;\">титул 070,154 «Контроль и Автоматика»;</li>\r\n 	<li style=\"text-align: justify;\">титул 078, «Производственный Экологический Мониторинг»;</li>\r\n 	<li style=\"text-align: justify;\">титул 129, «Наружные сети связи»;</li>\r\n 	<li style=\"text-align: justify;\">титул 112, «Автоматизация общеобменной вентиляции».</li>\r\n</ul>\r\n<p style=\"text-align: justify;\"><strong>Нами выполнены работы по проектам:</strong></p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: justify;\">«Комплекс по производству поливинилхлорида» в Нижегородской области;</li>\r\n 	<li style=\"text-align: justify;\">«Зайкинское ГПП» в Оренбургской области,</li>\r\n 	<li style=\"text-align: justify;\">ООО «КАМАЗ-Энерго»,</li>\r\n 	<li style=\"text-align: justify;\">НП «КАМАЗ-Автоспорт»</li>\r\n 	<li style=\"text-align: justify;\">ОАО «Алабуга-Волокно»,</li>\r\n 	<li style=\"text-align: justify;\">«Федеральный центр обработки данных» г. Городец Нижегородской области,</li>\r\n 	<li style=\"text-align: justify;\"> Иргизское месторождение ООО «Татнефть-Самара»,</li>\r\n 	<li style=\"text-align: justify;\">Котельная «Северо-Ашальчинская» Ашальчинского месторождения сверхвязкой нефти.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">ООО «Синтегра» было задействовано в капитальном и текущем ремонтах ПАО «Нижнекамскнефтехим», ОАО «ТАИФ-НК», ПАО «Нижнекамскшина», Нижнекамской ГЭС, Нижнекамской ТЭЦ, Заинской ГРЭС, Набережно-Челнинской ТЭЦ. Все перечисленные виды работ выполняются специалистами высокого уровня с использованием новейших технологий и специализированного оборудования. Это позволяет нам проводить работы в максимально сжатые сроки и на высочайшем уровне качества.</p>\r\n<p style=\"text-align: justify;\">В нашей компании трудятся опытные специалисты по монтажу систем КИПиА, систем связи, электротехнического оборудования, инженеры-наладчики средств КИПиА, АСУТП и рабочие других специальностей с большим опытом работ, высоким профессиональным уровнем и ответственностью.</p>\r\n<p style=\"text-align: justify;\">Общая численность сотрудников предприятия более 160 человек. Кроме этого, имеется возможность привлечения дополнительных специалистов к производственному процессу, а также организации производственного процесса выездного характера.</p>\r\n<p style=\"text-align: justify;\">Организация располагает как производственными и складскими помещениями, так и необходимым оборудованием и техникой, требуемым для производства работ. Также, в случае необходимости, имеется возможность приобрести дополнительное оборудование и технику, необходимые для бесперебойной работы.</p>\r\n<p style=\"text-align: justify;\">С целью создания привлекательных условий для Заказчика наша компания при выполнении контрактных обязательств готова максимально учитывать его особые требования, использовать местные строительные материалы, налаживать отношения с рекомендуемыми подрядчиками, осуществлять технический контроль подрядных работ и т.п.</p>\r\n&nbsp;','О компании','','publish','closed','closed','','o-kompanii','','','2019-10-26 18:49:26','2019-10-26 15:49:26','',0,'http://sintegra-nk.ru/?page_id=11',0,'page','',0),(12,1,'2019-10-26 16:52:44','2019-10-26 13:52:44','','О компании','','inherit','closed','closed','','11-revision-v1','','','2019-10-26 16:52:44','2019-10-26 13:52:44','',11,'http://sintegra-nk.ru/2019/10/26/11-revision-v1/',0,'revision','',0),(13,1,'2019-10-26 16:52:50','2019-10-26 13:52:50','<p style=\"text-align: center;\">Номер телефона: +7 (8555) 41-00-01</p>\r\n<p style=\"text-align: center;\">Адрес электронной почты: <a href=\"mailto:info@s-nk.su\">info@s-nk.su</a></p>\r\n<p style=\"text-align: center;\">Юридический адрес: 423570, Республика Татарстан, г. Нижнекамск, ул. Баки Урманче, д. 22, кв. 6</p>\r\n<p style=\"text-align: center;\">Почтовый адрес: 423582, РФ, РТ, г. Нижнекамск, ул. Кайманова, д. 16, ОПС-12, а/я 13</p>\r\n<p style=\"text-align: center;\">Адрес местонахождения: 423570, РФ, РТ, г. Нижнекамск, БСИ, ул. Заводская 3 В</p>\r\n<p style=\"text-align: center;\"><a href=\"https://goo.gl/maps/vqWVCgFxGjC6wiAYA\">Мы находимся здесь</a></p>\r\n<p style=\"text-align: center;\"><strong>Наша База</strong></p>\r\n\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td><img class=\"alignnone size-full wp-image-115\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_102959-4.png\" alt=\"\" /></td>\r\n<td><img class=\"alignnone wp-image-116 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103021-5.png\" alt=\"\" /></td>\r\n</tr>\r\n<tr>\r\n<td><img class=\"alignnone wp-image-117 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103024-4.png\" alt=\"\" /></td>\r\n<td><img class=\"alignnone wp-image-119 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103040-4.png\" alt=\"\" /></td>\r\n</tr>\r\n<tr>\r\n<td><img class=\"alignnone wp-image-120 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103100-2.png\" alt=\"\" /></td>\r\n<td><img class=\"alignnone wp-image-121 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103103-2.png\" alt=\"\" /></td>\r\n</tr>\r\n<tr>\r\n<td><img class=\"alignnone wp-image-122 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103126-2.png\" alt=\"\" /></td>\r\n<td><img class=\"alignnone wp-image-123 size-full\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/img_20190522_103143-2.png\" alt=\"\" /></td>\r\n</tr>\r\n</tbody>\r\n</table>','Контакты','','publish','closed','closed','','kontakty','','','2019-10-28 16:53:16','2019-10-28 13:53:16','',0,'http://sintegra-nk.ru/?page_id=13',0,'page','',0),(14,1,'2019-10-26 16:52:50','2019-10-26 13:52:50','','Контакты','','inherit','closed','closed','','13-revision-v1','','','2019-10-26 16:52:50','2019-10-26 13:52:50','',13,'http://sintegra-nk.ru/2019/10/26/13-revision-v1/',0,'revision','',0),(15,1,'2019-10-26 16:53:05','2019-10-26 13:53:05','<a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/lic_mchs_stranitsa_1.png\"><img class=\"alignnone wp-image-177 size-medium\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/lic_mchs_stranitsa_1-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a> <a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/lic_mchs_stranitsa_2.png\"><img class=\"alignnone wp-image-178 size-medium\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/lic_mchs_stranitsa_2-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a>','Лицензии','','publish','closed','closed','','licenzii','','','2019-10-27 15:52:41','2019-10-27 12:52:41','',9,'http://sintegra-nk.ru/?page_id=15',0,'page','',0),(16,1,'2019-10-26 16:53:05','2019-10-26 13:53:05','','Лицензии','','inherit','closed','closed','','15-revision-v1','','','2019-10-26 16:53:05','2019-10-26 13:53:05','',15,'http://sintegra-nk.ru/2019/10/26/15-revision-v1/',0,'revision','',0),(17,1,'2019-10-26 16:53:17','2019-10-26 13:53:17','<a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_montag_stranitsa_1-1.png\"><img class=\"alignnone size-medium wp-image-184\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_montag_stranitsa_1-1-215x300.png\" alt=\"\" width=\"215\" height=\"300\" /></a><a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_montag_stranitsa_2-1.png\"><img class=\"alignnone wp-image-185 size-medium\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_montag_stranitsa_2-1-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a><a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_proekt_stranitsa_1-2.png\"><img class=\"alignnone wp-image-186 size-medium\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_proekt_stranitsa_1-2-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a><a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_proekt_stranitsa_2-2.png\"><img class=\"alignnone wp-image-187 size-medium\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sro_proekt_stranitsa_2-2-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a>','Выписки из реестра СРО','','publish','closed','closed','','vypiski-iz-reestra-sro','','','2019-10-27 15:55:45','2019-10-27 12:55:45','',9,'http://sintegra-nk.ru/?page_id=17',0,'page','',0),(18,1,'2019-10-26 16:53:17','2019-10-26 13:53:17','','Выписки из реестра СРО','','inherit','closed','closed','','17-revision-v1','','','2019-10-26 16:53:17','2019-10-26 13:53:17','',17,'http://sintegra-nk.ru/2019/10/26/17-revision-v1/',0,'revision','',0),(19,1,'2019-10-26 16:53:24','2019-10-26 13:53:24','<a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/dec_020-1.png\"><img class=\"alignnone size-medium wp-image-190\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/dec_020-1-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a> <a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sert_004-1-1.png\"><img class=\"alignnone size-medium wp-image-191\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/sert_004-1-1-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a>','Сертификаты','','publish','closed','closed','','sertifikaty','','','2019-10-27 15:57:50','2019-10-27 12:57:50','',9,'http://sintegra-nk.ru/?page_id=19',0,'page','',0),(20,1,'2019-10-26 16:53:24','2019-10-26 13:53:24','','Сертификаты','','inherit','closed','closed','','19-revision-v1','','','2019-10-26 16:53:24','2019-10-26 13:53:24','',19,'http://sintegra-nk.ru/2019/10/26/19-revision-v1/',0,'revision','',0),(21,1,'2019-10-26 16:53:34','2019-10-26 13:53:34','<a href=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/uved_rtn.png\"><img class=\"alignnone size-medium wp-image-193\" src=\"http://sintegra-nk.ru/wp-content/uploads/2019/10/uved_rtn-212x300.png\" alt=\"\" width=\"212\" height=\"300\" /></a>','Уведомления Ростехнадзора','','publish','closed','closed','','uvedomleniya-rostexnadzora','','','2019-10-27 15:58:24','2019-10-27 12:58:24','',9,'http://sintegra-nk.ru/?page_id=21',0,'page','',0),(22,1,'2019-10-26 16:53:34','2019-10-26 13:53:34','','Уведомления Ростехнадзора','','inherit','closed','closed','','21-revision-v1','','','2019-10-26 16:53:34','2019-10-26 13:53:34','',21,'http://sintegra-nk.ru/2019/10/26/21-revision-v1/',0,'revision','',0),(23,1,'2019-10-26 16:53:50','2019-10-26 13:53:50','<p style=\"text-align: justify;\">Автоматизированная система диспетчерского управления (АСДУ) представляет собой совокупность различных средств, включая технические, аппаратные и программные, которые служат для автоматизации слаженной работы оборудования и персонала, а также обеспечивают рациональный контроль с диспетчерских пультов и пунктов.</p>\r\n<p style=\"text-align: justify;\">АСДУ имеют ряд существенных преимуществ. Основными достоинствами этих систем можно назвать следующее:</p>\r\n\r\n<ul style=\"text-align: justify;\">\r\n 	<li style=\"text-align: justify;\">обеспечение оперативного контроля над оборудованием и управление процессами;</li>\r\n 	<li style=\"text-align: justify;\">автоматизация процессов;</li>\r\n 	<li style=\"text-align: justify;\">хранение, обработка, анализ и передача информации на пульт диспетчера;</li>\r\n 	<li style=\"text-align: justify;\">осуществление связи между сотрудниками;</li>\r\n 	<li style=\"text-align: justify;\">информирование и регистрация сигналов об аварийных ситуациях;</li>\r\n 	<li style=\"text-align: justify;\">документирование и отчётность;</li>\r\n 	<li style=\"text-align: justify;\">учёт ресурсов;</li>\r\n 	<li style=\"text-align: justify;\">увеличение надёжности оборудования;</li>\r\n 	<li style=\"text-align: justify;\">значительное повышение уровня безопасности;</li>\r\n 	<li style=\"text-align: justify;\">максимальное снижение влияния человеческого фактора;</li>\r\n 	<li style=\"text-align: justify;\">отслеживание возникновения нештатных ситуаций;</li>\r\n 	<li style=\"text-align: justify;\">обеспечение своевременной реакции в экстренных случаях;</li>\r\n 	<li style=\"text-align: justify;\">увеличение продуктивности работы</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">Автоматизированная система диспетчерского управления проектируется индивидуально и может контролировать различные инженерные системы, в зависимости от нужд конкретного заказчика, например безопасность и видеонаблюдение, отопление и водоснабжение, электропитание, доступ свежего воздуха, вентиляция, пожарная система, контроль над возникновением и устранением возгораний.</p>','Монтажные и пусконаладочные работы систем АСДУ','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistem-asdu-ems','','','2019-10-28 10:35:25','2019-10-28 07:35:25','',7,'http://sintegra-nk.ru/?page_id=23',2,'page','',0),(24,1,'2019-10-26 16:53:50','2019-10-26 13:53:50','','Монтажные и пусконаладочные работы систем АСДУ ЭМС','','inherit','closed','closed','','23-revision-v1','','','2019-10-26 16:53:50','2019-10-26 13:53:50','',23,'http://sintegra-nk.ru/2019/10/26/23-revision-v1/',0,'revision','',0),(25,1,'2019-10-26 16:54:02','2019-10-26 13:54:02','<p style=\"text-align: justify;\">В вопросах организации, управления и работы различных технологических процессов важнейшая роль отводится, как к неотъемлемой части, системам и устройствам связи. Это связано с территориальной распределённостью объектов. Также в пределах объекта могут располагаться десятки отделов, складов, помещений и различных структур, которые постоянно взаимодействуют. Организовать надёжную и оперативную связь в подобном месте очень непросто. Успешно удовлетворить требования к взаимосвязи таких объектов могут системы внутренней связи.</p>\r\n<p style=\"text-align: justify;\">Система внутренней связи – совокупность аппаратных и программных средств, которые позволяют реализовать взаимосвязь между персоналом внутри объекта. Центром внутренней телефонной системы на любом объекте является собственная АТС, отличающаяся от стандартных АТС меньшим количеством абонентов и отделением внешней и внутренней сети. Внутренние сети, реализованные с помощью различных технологий широко распространены и применяются в различных видах организаций, например бизнес-центры и торговые предприятия, крупные производства и промышленные объекты, транспортные компании, службы управления, государственные учреждения и другие организации.</p>\r\n<p style=\"text-align: justify;\">Системы внутренней телефонной связи являются альтернативой другим способам коммуникации, применяемым на производствах и в других видах организаций. Независимо от рода и специфики деятельности предприятия, внутренняя связь значительно упрощает коммуникацию между персоналом, что делает работу сотрудников более продуктивной и эффективной. Относительно низкая стоимость реализации такой системы также играет в пользу её внедрения.</p>','Монтажные и пусконаладочные работы систем связи','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistem-svyazi','','','2019-10-28 10:35:38','2019-10-28 07:35:38','',7,'http://sintegra-nk.ru/?page_id=25',2,'page','',0),(26,1,'2019-10-26 16:54:02','2019-10-26 13:54:02','','Монтажные и пусконаладочные работы систем связи','','inherit','closed','closed','','25-revision-v1','','','2019-10-26 16:54:02','2019-10-26 13:54:02','',25,'http://sintegra-nk.ru/2019/10/26/25-revision-v1/',0,'revision','',0),(27,1,'2019-10-26 16:54:10','2019-10-26 13:54:10','<p style=\"text-align: justify;\">Системы видеонаблюдения предназначены для защиты объекта путём мониторинга за его территорией. Позже полученная с видеокамер информация анализируется, обрабатывается и архивируется на цифровом носителе. Подобным образом, система видеонаблюдения не только следит за объектом, но и записывает полученную видеоинформацию, обрабатывает её и хранит.</p>\r\n<p style=\"text-align: justify;\">Монтаж видеонаблюдения производится так, чтобы просматривать наиболее важные места объекта, где расположены материальные ценности. Чаще всего видеокамеры устанавливаются так, чтобы на мониторе отображались стоянки автомобилей, полки торговых залов, помещения складов, места массового скопления людей и т. д. Помимо этого видеонаблюдение контролирует места, через которые можно попасть на объект и выйти из него – проходные, двери, заборы, ворота и другое. На предприятиях и офисах видеонаблюдение может выполнять функцию контроля за перемещаемыми объектами.</p>\r\n<p style=\"text-align: justify;\">В определенных случаях монтаж видеонаблюдения производится в производственных помещениях, чтобы иметь возможность контролировать правильность технологического процесса, как в промышленности, так и в сфере услуг. При проектировании системы видеонаблюдения учитываются определенные критерии. Для подбора наиболее подходящих технических средств, нужно предварительно определить, каким требованиям она должна удовлетворять, какие места она должна контролировать, а также какой объём видеоинформации должен быть сохранен. Для получения таких данных необходимо техническое обследование всего охраняемого объекта.</p>','Монтажные и пусконаладочные работы систем видеонаблюдения','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistem-videonablyudeniya','','','2019-10-28 10:36:03','2019-10-28 07:36:03','',7,'http://sintegra-nk.ru/?page_id=27',2,'page','',0),(28,1,'2019-10-26 16:54:10','2019-10-26 13:54:10','','Монтажные и пусконаладочные работы систем видеонаблюдения','','inherit','closed','closed','','27-revision-v1','','','2019-10-26 16:54:10','2019-10-26 13:54:10','',27,'http://sintegra-nk.ru/2019/10/26/27-revision-v1/',0,'revision','',0),(29,1,'2019-10-26 16:54:17','2019-10-26 13:54:17','<p style=\"text-align: justify;\">По определению, пожар – это процесс неконтролируемого горения, которое способно нанести значительный материальный ущерб, а также может угрожать здоровью человека. В отдельных случаях распространение неуправляемого огня может привести к разрушительным и смертоносным последствиям. Учитывая тяжелые последствия, к которым может привести пожар, вопросам пожарной безопасности уделяется повышенное внимание на государственном уровне. При этом одним из основных способов, препятствующих возникновению и распространению пожаров, является оснащение объектов специальными техническими средствами, к которым относятся системы пожарной сигнализации и автоматизации пожаротушения.</p>\r\n<p style=\"text-align: justify;\">Пожарная сигнализация – это одна из базовых составляющих любой системы пожарной безопасности. При этом эффективность последней значительно повышается при использовании дополнительных технических средств, к которым относятся такие системы, как оповещение людей о пожаре, дымоудаление, охранная сигнализация, видеонаблюдение, контроль доступа и др.</p>\r\n<p style=\"text-align: justify;\">Пожарная сигнализация предназначена для своевременного обнаружения местонахождения возгорания и передачи специально сформированных сигналов на системы пожарного оповещения и автоматического пожаротушения. В общем случае она состоит из извещателей и приёмно-контрольной аппаратуры, с помощью которой осуществляется обработка и регистрация полученных данных, а также формирование команд, включающих периферийные устройства (звуковые и световые извещатели, блок управления внешними устройствами и пр.).</p>\r\n<p style=\"text-align: justify;\">Каждый объект, в котором предполагается установка технических средств пожарной сигнализации и пожаротушения, по своему уникален и имеет свои отличительные особенности. Поэтому универсального решения по их установке не существует. В каждом конкретном случае тщательно изучаются особенности объекта, и разрабатывается соответствующий проект, предусматривающий все нюансы выбора, установки и монтажа оборудования.</p>','Монтажные и пусконаладочные работы пожарной сигнализации и автоматизации пожаротушения','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-pozharnoj-signalizacii-i-avtomatizacii-pozharotusheniya','','','2019-10-28 10:36:14','2019-10-28 07:36:14','',7,'http://sintegra-nk.ru/?page_id=29',3,'page','',0),(30,1,'2019-10-26 16:54:17','2019-10-26 13:54:17','','Монтажные и пусконаладочные работы пожарной сигнализации и автоматизации пожаротушения','','inherit','closed','closed','','29-revision-v1','','','2019-10-26 16:54:17','2019-10-26 13:54:17','',29,'http://sintegra-nk.ru/2019/10/26/29-revision-v1/',0,'revision','',0),(31,1,'2019-10-26 16:54:27','2019-10-26 13:54:27','<p style=\"text-align: justify;\">По определению, пожар – это процесс неконтролируемого горения, которое способно нанести значительный материальный ущерб, а также может угрожать здоровью человека. В отдельных случаях распространение неуправляемого огня может привести к разрушительным и смертоносным последствиям. Учитывая тяжелые последствия, к которым может привести пожар, вопросам пожарной безопасности уделяется повышенное внимание на государственном уровне. При этом одним из основных способов, препятствующих возникновению и распространению пожаров, является оснащение объектов специальными техническими средствами, к которым относится система автоматизации пожаротушения.</p>\r\n<p style=\"text-align: justify;\">Системы автоматического пожаротушения в общем случае призваны начинать тушение очага возгорания до прибытия пожарных, то есть на ранней стадии его развития. Автоматические установки пожаротушения оснащены специальными ёмкостями, которые заполнены составами, способными эффективно прекратить процесс горения. При этом лучшими считаются комбинированные установки пожаротушения, которые наряду с автоматическим включением допускают и ручной запуск с диспетчерского пульта.</p>\r\n<p style=\"text-align: justify;\">Существующие в настоящее время системы автоматического тушения пожара делят на следующие типы:</p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: justify;\">водяные установки;</li>\r\n 	<li style=\"text-align: justify;\">агрегаты тушения пожара пеной;</li>\r\n 	<li style=\"text-align: justify;\">системы порошкового пожаротушения;</li>\r\n 	<li style=\"text-align: justify;\">газовые системы пожаротушения.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">Использование систем газового и порошкового пожаротушения усложняется тем, что вещества, используемые при ликвидации возгорания, опасны для здоровья и жизни человека. Поэтому помещение и вход в него должны быть оборудованы специальными звуковыми и визуальными оповещателями, предупреждающими обслуживающий персонал о начале работы системы автоматического пожаротушения. При этом людям должно быть предоставлено время для того, чтобы покинуть помещение.</p>\r\n<p style=\"text-align: justify;\">Каждый объект, в котором предполагается установка технических средств автоматизации пожаротушения, по своему уникален и имеет свои отличительные особенности. Поэтому универсального решения по их установке не существует. В каждом конкретном случае тщательно изучаются особенности объекта, и разрабатывается соответствующий проект, предусматривающий все нюансы выбора, установки и монтажа оборудования.</p>','Монтажные и пусконаладочные работы автоматики противопожарных мероприятий','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-avtomatiki-protivopozharnyx-meropriyatij','','','2019-10-28 10:36:22','2019-10-28 07:36:22','',7,'http://sintegra-nk.ru/?page_id=31',3,'page','',0),(32,1,'2019-10-26 16:54:27','2019-10-26 13:54:27','','Монтажные и пусконаладочные работы автоматики противопожарных мероприятий','','inherit','closed','closed','','31-revision-v1','','','2019-10-26 16:54:27','2019-10-26 13:54:27','',31,'http://sintegra-nk.ru/2019/10/26/31-revision-v1/',0,'revision','',0),(33,1,'2019-10-26 16:53:36','2019-10-26 13:53:36','<p style=\"text-align: justify;\">Охранная сигнализация предназначена для обнаружения проникновения или его попыток на оборудованный ею объект и формирования соответствующих оповещений (формирование звукового и (или) светового сигнала, передача сообщения о тревоге на удаленный монитор). Принцип ее действия заключается в преобразовании извещателями обнаруженного воздействия в электрический сигнал, передачи его на пульт управления, который предназначен для управления устройствами оповещения и передачи информации.</p>\r\n<p style=\"text-align: justify;\">Основным требованием к любому охранному оборудованию является обеспечение надежности работы в различных режимах. Немаловажно как точно будет обнаруживаться место нарушения. С этой целью применяется разделение охраняемой территории на максимально мелкие зоны, каждая из которых контролируется отдельно. Идеальным является отслеживание состояния каждого датчика. Это является возможным при использовании адресного построения системы.</p>\r\n<p style=\"text-align: justify;\">Следующее требование к охранной сигнализации — сохранение работоспособности при отключении сетевого электропитания. Для систем, установленных на крупных объектах, энергопотребление всего оборудования может оказаться таким, что подобрать нужные характеристики блока питания окажется затруднительным. В этом случае нужно разделить электропотребляющие устройства на группы, подключив каждую к отдельному источнику напряжения.</p>\r\n<p style=\"text-align: justify;\">Ещё одно немаловажное требование — исключение возможности несанкционированного воздействия на систему с целью ухудшения её характеристик или полного вывода из строя. Применение технических средств с характеристиками, позволяющими предотвратить, минимизировать или заблаговременно обнаружить последствия постороннего вмешательства позволяет значительно повысить надёжность сигнализации.</p>\r\n<p style=\"text-align: justify;\">Немаловажное значение имеет также своевременное техническое обслуживание сигнализации с соблюдением всех требований, предъявляемых к его проведению.</p>','Монтажные и пусконаладочные работы охранной сигнализации','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-oxrannoj-signalizacii','','','2019-10-28 10:35:53','2019-10-28 07:35:53','',7,'http://sintegra-nk.ru/?page_id=33',2,'page','',0),(34,1,'2019-10-26 16:54:36','2019-10-26 13:54:36','','Монтажные и пусконаладочные работы охранной сигнализации','','inherit','closed','closed','','33-revision-v1','','','2019-10-26 16:54:36','2019-10-26 13:54:36','',33,'http://sintegra-nk.ru/2019/10/26/33-revision-v1/',0,'revision','',0),(35,1,'2019-10-26 18:00:47','2019-10-26 15:00:47','<p style=\"text-align: justify;\">В современном мире безопасности на объектах различной направленности уделяется особое внимание, вне зависимости от того, крупное это предприятие или небольшой офис, школа или торговый центр. Наряду с традиционным штатом сотрудников охраны, занимающихся выполнением этих функций, используются различные технические системы, расширяющие возможности и функциональность служб охраны – системы контроля и управления доступом (СКУД).</p>\r\n<p style=\"text-align: justify;\">Система контроля и управления доступом – это элемент системы безопасности, созданный на основе технических устройств и электронных систем управления, объединённых в единую сеть, работающую на специально разработанном программном обеспечении. Кроме этого, система контроля доступа позволяет автоматизировать учёт рабочего времени на предприятии и в офисе, тем самым облегчая работу кадровой службы организации.</p>\r\n<p style=\"text-align: justify;\">Автономные СКУД – это системы, обеспечивающие контроль за отдельным (офисом, магазином и т.д.) или несколькими помещениями, объединёнными общим назначением, когда управление работой осуществляется при помощи отдельного (автономного) контроллера. В таких установках контроллер управления не связан с прочими электронными устройствами управления, а работает автономно. Точкой доступа на контролируемую территорию, как правило, выступает входная дверь. В качестве исполнительного механизма в автономных системах контроля применяется электронный замок или защёлка, а идентификатором – карта контроля доступа с различными типами считывателей (штриховой, магнитный, проксимити). Автономный контроллер, как правило, работает только «на вход» контролируемой территории, а «на выход» используются кнопки управления или датчики.</p>\r\n<p style=\"text-align: justify;\">Сетевые СКУД – это системы оснащаются более мощным и функциональным контроллером (или группой контроллеров), обеспечивающим работу СКУД на значительных по площади помещениях, где одновременно может находиться большое количество людей. В таких системах точками доступа служат проходные предприятий или иные сооружения, а в качестве исполнительного механизма используются турникеты или шлюзы. Идентификаторы могут быть различного типа, а сами исполнительные механизмы оснащаются дистанционными считывателями.</p>\r\n<p style=\"text-align: justify;\">В качестве дополнительных функций СКУД может быть совмещена с системами видеонаблюдения и охранно-пожарной сигнализации. Также в качестве дополнения могут выступать способы передачи беспроводного сигнала.</p>','Монтажные и пусконаладочные работы систем контроля и управления доступом, охраны периметра','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistem-kontrolya-i-upravleniya-dostupom-oxrany-perimetra','','','2019-10-28 10:36:37','2019-10-28 07:36:37','',7,'http://sintegra-nk.ru/?page_id=35',4,'page','',0),(36,1,'2019-10-26 16:54:47','2019-10-26 13:54:47','','Монтажные и пусконаладочные работы систем контроля и управления доступом, охраны периметра','','inherit','closed','closed','','35-revision-v1','','','2019-10-26 16:54:47','2019-10-26 13:54:47','',35,'http://sintegra-nk.ru/2019/10/26/35-revision-v1/',0,'revision','',0),(37,1,'2019-10-26 18:01:55','2019-10-26 15:01:55','<p style=\"text-align: justify;\">Система оповещения и управления эвакуацией людей при пожаре (СОУЭ) – комплекс организационных мероприятий и технических средств, предназначенных для своевременной передачи информации о возникновении пожара и путях эвакуации, а также для обеспечения безопасной эвакуации людей при пожаре путём включения технических средств, предотвращения паники.</p>\r\n<p style=\"text-align: justify;\">Управление эвакуацией в случае пожара продумывается еще при планировке зданий, которые должны иметь такое пространственное исполнение, которое обеспечит быстрый выход из зон поражения огнём или продуктами горения.</p>\r\n<p style=\"text-align: justify;\">Правильная функциональность обеспечивается:</p>\r\n<p style=\"text-align: justify;\">- путём подачи световых, звуковых сигналов, трансляцией записей специально составленных текстов с призывами и инструкциями о действиях, направлениях движения;</p>\r\n<p style=\"text-align: justify;\">- включением аварийного освещения;</p>\r\n<p style=\"text-align: justify;\">- размещением в обязательном порядке освещаемых знаков пожарной безопасности на маршрутах движения людей в безопасные зоны;</p>\r\n<p style=\"text-align: justify;\">- работой удалённо открываемых запорных устройств на выходах;</p>\r\n<p style=\"text-align: justify;\">- созданием связи между диспетчерами пожарного поста и зоной оповещения и другими методами.</p>\r\n<p style=\"text-align: justify;\">Таким образом, в составе систем оповещения о пожаре и управления эвакуацией входят такие устройства, как оповещатели, световые табло, указатели направления, системы связи для информирования дежурных и персонала, электроника контроля доступа для открывания запоров, приборы управления СОУЭ.</p>\r\n<p style=\"text-align: justify;\">В зависимости от степени автономности работы СОУЭ может быть автономной или работать как часть большей системы. Также выделяют 5 типов СОУЭ в зависимости от количества этажей в здании, ответственностью объекта и другими факторами.</p>\r\n\r\n<ul style=\"text-align: justify;\">\r\n 	<li style=\"text-align: justify;\">1 тип характеризуется наличием звуковых и световых оповещателей, сигналов, сирен, которые подаются тревожное оповещение во все помещения, где могут находиться люди. Работает одна линия, все оповещатели включаются одновременно.</li>\r\n 	<li style=\"text-align: justify;\">2 тип предусматривает наличие тех же технических средств, а также установку световых указателей направления движения при эвакуации, световых указателей «Выход».</li>\r\n 	<li style=\"text-align: justify;\">3 тип предполагает дополнительное наличие ретрансляторов аудио обращений, которые будут ретранслировать обращения о путях эвакуации и предотвращать панику среди людей на объекте. Также предполагается независимое включение линий оповещения, работает две и более линии, создаются зоны оповещения.</li>\r\n 	<li style=\"text-align: justify;\">4 тип кроме всех вышеуказанных способов оповещения и управления эвакуацией на нескольких независимых линиях, предполагает наличие голосовой связи диспетчера с зонами оповещения. Есть возможность реализовать различные варианты эвакуации из зон здания, управлять персоналом и эвакуируемыми людьми с помощью обратной связи.</li>\r\n 	<li style=\"text-align: justify;\">5 тип предполагает внедрение полной автоматизации и различных вариантов координации и централизованного управления выводом групп с единого поста.</li>\r\n</ul>','Монтажные и пусконаладочные работы системы оповещения и управления эвакуацией','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistemy-opoveshheniya-i-upravleniya-evakuaciej','','','2019-10-28 10:36:42','2019-10-28 07:36:42','',7,'http://sintegra-nk.ru/?page_id=37',4,'page','',0),(38,1,'2019-10-26 16:54:55','2019-10-26 13:54:55','','Монтажные и пусконаладочные работы системы оповещения и управления эвакуацией','','inherit','closed','closed','','37-revision-v1','','','2019-10-26 16:54:55','2019-10-26 13:54:55','',37,'http://sintegra-nk.ru/2019/10/26/37-revision-v1/',0,'revision','',0),(39,1,'2019-10-26 16:56:04','2019-10-26 13:56:04','<p style=\"text-align: justify;\">Системы громкоговорящей связи (ГГС) и громкоговорящего оповещения (ГГО) с давних времён применяются на промышленных объектах, где из-за специфичных условий эксплуатации обычная телефония не подходит, а также, если наличие ГГС регламентируется руководящими документами предприятия. Они используются, например, для быстрой связи диспетчера с персоналом на рабочих местах, предупреждения об авариях, оповещения населения о чрезвычайных ситуациях.</p>\r\n<p style=\"text-align: justify;\">В настоящее время для этих целей применяются специализированные решения и переговорные устройства самых разных типов (в том числе всепогодные и взрывозащищенные пульты, IP-телефоны, рабочие места на базе ПК).</p>\r\n<p style=\"text-align: justify;\">Традиционно на предприятиях используются цифровые системы громкоговорящей и диспетчерской связи. Они включают в себя центральный узел, который обеспечивает коммутацию сигналов между переговорными устройствами. Этот узел обычно содержит коммутационную матрицу, хотя есть как минимум одно решение, в котором абонентские платы устанавливают соединение между собой самостоятельно. Центральный узел конструктивно выполняется в виде шкафа, содержащего коммутационные процессоры, абонентские комплекты, блок питания и различные вспомогательные устройства. В центральный узел могут включаться как переговорные устройства и другие терминалы системы диспетчерской связи, так и абонентские пункты системы громкого оповещения, также есть решения, где обе системы имеют собственные центральные устройства.</p>\r\n<p style=\"text-align: justify;\">Что действительно отличает ГГС от обычной телефонии, так это конструкция терминального оборудования, обусловленная специфическими требованиями среды их применения. Устройства, которые работают в сложных условиях эксплуатации, имеют прочный корпус из металла или усиленного негорючего пластика, обеспечивающий высокую степень защиты от пыли и влаги. Такие устройства зачастую не имеют номеронабирателя и работают в полудуплексном режиме (диспетчер обращается к нужному абоненту напрямую, для ответа нужно нажать и удерживать кнопку на терминале). В местах с высоким уровнем производственного шума используются микрофоны с шумоподавлением и внешние рупорные громкоговорители, такие терминалы используют расширенную полосу частот для передачи голоса. Кроме того, переговорные устройства снабжены оптическим индикатором вызова.</p>\r\n<p style=\"text-align: justify;\">Для офисного применения приобрели популярность пульты на основе ПК с сенсорным монитором. На таком дисплее оператор может видеть одновременно порядка сотни абонентов с индикацией их состояния, очередь входящих вызовов и много другой информации.</p>\r\n<p style=\"text-align: justify;\">К другому типу терминального оборудования можно отнести громкоговорители оповещения, подключаемые через усилители мощности, сирены аварийной тревоги, видеокамеры, а также датчики тревожной сигнализации. Информация с датчиков может быть выведена на пульт диспетчера, который оперативно оповестит сотрудников и службу экстренного вызова. В аэропортах, железнодорожных и морских вокзалах, станциях метро устанавливаются колонны экстренного вызова, с помощью которых пассажир может обратиться в справочную службу, вызвать сотрудников служб экстренного вызова.</p>','Монтажные и пусконаладочные работы громкоговорящего оповещения','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-gromkogovoryashhego-opoveshheniya','','','2019-10-28 10:36:56','2019-10-28 07:36:56','',7,'http://sintegra-nk.ru/?page_id=39',5,'page','',0),(40,1,'2019-10-26 16:55:04','2019-10-26 13:55:04','','Монтажные и пусконаладочные работы громкоговорящего оповещения','','inherit','closed','closed','','39-revision-v1','','','2019-10-26 16:55:04','2019-10-26 13:55:04','',39,'http://sintegra-nk.ru/2019/10/26/39-revision-v1/',0,'revision','',0),(45,1,'2019-10-26 16:55:27','2019-10-26 13:55:27','<p style=\"text-align: justify;\">Автоматические устройства контроля за работой вентиляционной системы предназначены для поддержания комфортных условий в производственных и жилых помещениях. Если раньше автоматизированные системы отопления и вентиляции встречались преимущественно на объектах с особыми требованиями к условиям внутреннего микроклимата (библиотеки, архивы, склады, музеи, оранжереи и др.), то теперь эти технологии распространяются и на обычные офисные здания, многофункциональные многоэтажки и жилые (как частные, так и многоквартирные) дома, а также производственные объекты различного назначения.</p>\r\n<p style=\"text-align: justify;\">Современные системы – это комплекс автоматического управления микроклиматом помещения. Для поддержки слаженной работы всех механизмов и устройств устанавливается сложная аппаратура с различными датчиками и реле. Только такое обустройство щита автоматики позволяет корректировать действие всей системы вентиляции. Автоматизация систем вентиляции монтируется для решения проблем при использовании вентиляционного оборудования и механизмов.</p>\r\n<p style=\"text-align: justify;\">Основные задачи, выполняемые автоматикой вентиляции:</p>\r\n\r\n<ul style=\"text-align: justify;\">\r\n 	<li style=\"text-align: justify;\">решение задач по управлению и мониторингу нормальной работы схемы. Должен устанавливаться сигнализатор аварии, опасных режимах эксплуатации оборудования. Новые разработки позволяют управлять работой схемы удаленно. Оператор наблюдает за функционированием устройства, может вносить коррективы, устанавливать оптимальные режимы.</li>\r\n 	<li style=\"text-align: justify;\">произведение индивидуального анализа и мониторинга работы каждого отдельного механизма и общей деятельности схемы вентиляции. Датчики устройства доставляют информацию, автоматика производит исследование ситуации и вносит корректировки в работу вентиляционного оборудования. В случае аварии, подается сигнал на кнопку пуска для выключения оборудования.</li>\r\n 	<li style=\"text-align: justify;\">осуществляет защиту клапанов и водяного контура нагрева от низких температур, не позволяет опускаться температуре до критического уровня.</li>\r\n 	<li style=\"text-align: justify;\">обеспечивает возможность управления процессом вентилирования помещения, переключая режимы эксплуатации оборудования. При перепадах нагрузки, температуры в помещении – система управления способна понижать скорость вращения вентиляторов, полностью выключать оборудование и поддерживать комфортные условия в обслуживаемом помещении.</li>\r\n 	<li style=\"text-align: justify;\">в случае короткого замыкания и других аварийных ситуаций, производит блокировку механизмов, для исключения пожара и поражения людей током.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">Сложность выполняемой работы зависит от укомплектованности щита автоматического устройства. Выпускается ряд типов приборов, устройств и датчиков для создания автоматики управления вентиляцией. Для управления отдельным процессом, предназначены механизмы контроля. Но устройства не только контролируют весь процесс, но и управляют эксплуатацией одного участка схемы. Поэтому, в состав автоматики входят десятки различных реле, датчиков и других приборов. Но данные приборы производят локальное регулирование работы системы или делают замеры. Контроль и определение общего уровня безопасности, всего цикла работы вентиляционной системы, осуществляется с помощью шкафа центрального управления устройства вентиляции.</p>\r\n<p style=\"text-align: justify;\">Сложность системы можно понять, ознакомившись с полным списком оборудования данного устройства. Количество определенных датчиков или реле может быть значительным, а некоторые приборы представлены в единственном числе.</p>','Монтажные и пусконаладочные работы системы автоматизации отопления и вентиляции','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistemy-avtomatizacii-otopleniya-i-ventilyacii','','','2019-10-28 10:37:01','2019-10-28 07:37:01','',7,'http://sintegra-nk.ru/?page_id=45',5,'page','',0),(46,1,'2019-10-26 16:55:27','2019-10-26 13:55:27','','Монтажные и пусконаладочные работы системы автоматизации отопления и вентиляции','','inherit','closed','closed','','45-revision-v1','','','2019-10-26 16:55:27','2019-10-26 13:55:27','',45,'http://sintegra-nk.ru/2019/10/26/45-revision-v1/',0,'revision','',0),(47,1,'2019-10-26 16:55:34','2019-10-26 13:55:34','<p style=\"text-align: justify\">ООО «Синтегра» осуществляет комплекс монтажных и пусконаладочных работ систем автоматизации КИПиА и АСУТП, на предприятиях, промышленных и иных объектах. Системы подобного рода представляют собой целый комплекс программных и технических средств, которые обеспечивают регулирование объектов в производственной сфере.</p>\r\n\r\n<p style=\"text-align: justify\">Пусконаладочные работы по системам автоматизации, согласно СНиП, осуществляются в три этапа:</p>\r\n\r\n<p style=\"text-align: justify\">Первый этап включает: подготовительные работы, изучение рабочей документации, основные характеристики приборов и средств автоматизации.</p>\r\n\r\n<p style=\"text-align: justify\">Производится проверка приборов и средств автоматизации с необходимой регулировкой отдельных элементов аппаратуры. При проверке приборов и средств автоматизации проверяют соответствие основных технических характеристик аппаратуры требованиям, установленным в паспортах и инструкциях предприятий-изготовителей.</p>\r\n\r\n<p style=\"text-align: justify\">На втором этапе после завершения монтажа систем автоматизации выполняются работы по их автономной наладке.</p>\r\n\r\n<p style=\"text-align: justify\">На третьем этапе выполняются работы по комплексной наладке систем автоматизации, доведению параметров настройки приборов и средств автоматизации, каналов связи до значений, при которых системы автоматизации могут быть использованы в эксплуатации.</p>\r\n\r\n<p style=\"text-align: justify\">Пусконаладочные работы по системам автоматизации следует проводить в соответствии с требованиями, приведенными в рабочей документации, инструкциях предприятий-изготовителей приборов и средств автоматизации или в отраслевых правилах приемки в эксплуатацию законченных строительством объектов. Проведение монтажных и пусконаладочных работ систем КИПиА и АСУТП завершается приемкой объекта в эксплуатацию.</p>','Монтажные и пусконаладочные работы систем автоматизации КИПиА и АСУТП','','publish','closed','closed','','montazhnye-i-puskonaladochnye-raboty-sistem-avtomatizacii-kipia-i-asutp','','','2019-10-26 18:40:23','2019-10-26 15:40:23','',7,'http://sintegra-nk.ru/?page_id=47',0,'page','',0),(48,1,'2019-10-26 16:55:34','2019-10-26 13:55:34','','Монтажные и пусконаладочные работы систем автоматизации КИПиА и АСУТП','','inherit','closed','closed','','47-revision-v1','','','2019-10-26 16:55:34','2019-10-26 13:55:34','',47,'http://sintegra-nk.ru/2019/10/26/47-revision-v1/',0,'revision','',0),(49,1,'2019-10-26 16:54:41','2019-10-26 13:54:41','<p style=\"text-align: justify;\">Электромонтажные работы – это специальный вид строительных работ, выполняемых во время возведения и реконструкции зданий и сооружений разного назначения, которые непременно связаны с профессиональным монтажом электрических сетей. Это воздушные, кабельные линии электропередачи, проводов тока, электрических проводов и т.д., а также различного электрооборудования, к которому относятся электрические машины, распределительные пункты, пульты управления и многое другое.</p>\r\n<p style=\"text-align: justify;\">Наша компания предоставляет услуги по проведению электромонтажных работ любой сложности. Все работы производятся в соответствии с ГОСТ, СНиП, ПУЭ.</p>','Электромонтажные работы','','publish','closed','closed','','elektromontazhnye-raboty','','','2019-10-28 10:37:04','2019-10-28 07:37:04','',7,'http://sintegra-nk.ru/?page_id=49',5,'page','',0),(50,1,'2019-10-26 16:55:41','2019-10-26 13:55:41','','Электромонтажные работы','','inherit','closed','closed','','49-revision-v1','','','2019-10-26 16:55:41','2019-10-26 13:55:41','',49,'http://sintegra-nk.ru/2019/10/26/49-revision-v1/',0,'revision','',0),(51,1,'2019-10-26 16:55:59','2019-10-26 13:55:59','','Главная','','publish','closed','closed','','glavnaya','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',0,'http://sintegra-nk.ru/?p=51',1,'nav_menu_item','',0),(52,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','52','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',0,'http://sintegra-nk.ru/?p=52',16,'nav_menu_item','',0),(53,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','53','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',9,'http://sintegra-nk.ru/?p=53',18,'nav_menu_item','',0),(54,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','54','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',9,'http://sintegra-nk.ru/?p=54',17,'nav_men