:11:16','',7,'http://sintegra-nk.ru/?p=65',8,'nav_menu_item','',0),(66,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','66','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=66',9,'nav_menu_item','',0),(67,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','67','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=67',10,'nav_menu_item','',0),(68,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','68','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=68',11,'nav_menu_item','',0),(69,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','69','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=69',12,'nav_menu_item','',0),(70,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','70','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=70',13,'nav_menu_item','',0),(71,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','71','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=71',14,'nav_menu_item','',0),(73,1,'2019-10-26 16:55:59','2019-10-26 13:55:59',' ','','','publish','closed','closed','','73','','','2019-11-28 10:11:16','2019-11-28 07:11:16','',7,'http://sintegra-nk.ru/?p=73',15,'nav_menu_item','',0),(75,1,'2019-10-26 17:31:42','2019-10-26 14:31:42','','plitka1','','inherit','open','closed','','plitka1','','','2019-10-26 17:31:42','2019-10-26 14:31:42','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka1.jpg',0,'attachment','image/jpeg',0),(76,1,'2019-10-26 17:31:42','2019-10-26 14:31:42','','plitka2','','inherit','open','closed','','plitka2','','','2019-10-26 17:31:42','2019-10-26 14:31:42','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka2.jpg',0,'attachment','image/jpeg',0),(77,1,'2019-10-26 17:31:42','2019-10-26 14:31:42','','plitka3','','inherit','open','closed','','plitka3','','','2019-10-26 17:31:42','2019-10-26 14:31:42','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka3.jpg',0,'attachment','image/jpeg',0),(78,1,'2019-10-26 17:31:42','2019-10-26 14:31:42','','plitka4','','inherit','open','closed','','plitka4','','','2019-10-26 17:31:42','2019-10-26 14:31:42','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka4.jpg',0,'attachment','image/jpeg',0),(79,1,'2019-10-26 17:31:43','2019-10-26 14:31:43','','plitka5','','inherit','open','closed','','plitka5','','','2019-10-26 17:31:43','2019-10-26 14:31:43','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka5.jpg',0,'attachment','image/jpeg',0),(80,1,'2019-10-26 17:31:43','2019-10-26 14:31:43','','plitka6','','inherit','open','closed','','plitka6','','','2019-10-26 17:31:43','2019-10-26 14:31:43','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka6.jpg',0,'attachment','image/jpeg',0),(81,1,'2019-10-26 17:31:43','2019-10-26 14:31:43','','plitka7','','inherit','open','closed','','plitka7','','','2019-10-26 17:31:43','2019-10-26 14:31:43','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka7.jpg',0,'attachment','image/jpeg',0),(82,1,'2019-10-26 17:31:43','2019-10-26 14:31:43','','plitka8','','inherit','open','closed','','plitka8','','','2019-10-26 17:31:43','2019-10-26 14:31:43','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka8.jpg',0,'attachment','image/jpeg',0),(83,1,'2019-10-26 17:31:44','2019-10-26 14:31:44','','plitka9','','inherit','open','closed','','plitka9','','','2019-10-26 17:31:44','2019-10-26 14:31:44','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka9.jpg',0,'attachment','image/jpeg',0),(84,1,'2019-10-26 17:31:44','2019-10-26 14:31:44','','plitka10','','inherit','open','closed','','plitka10','','','2019-10-26 17:31:44','2019-10-26 14:31:44','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka10.jpg',0,'attachment','image/jpeg',0),(85,1,'2019-10-26 17:31:44','2019-10-26 14:31:44','','plitka11','','inherit','open','closed','','plitka11','','','2019-10-26 17:31:44','2019-10-26 14:31:44','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka11.jpg',0,'attachment','image/jpeg',0),(86,1,'2019-10-26 17:31:44','2019-10-26 14:31:44','','plitka12','','inherit','open','closed','','plitka12','','','2019-10-26 17:31:44','2019-10-26 14:31:44','',25,'http://sintegra-nk.ru/wp-content/uploads/2019/10/plitka12.jpg',0,'attachment','image/jpeg',0),(87,1,'2019-10-26 18:11:23','2019-10-26 15:11:23','<p style=\"text-align: justify;\">Системы автоматического пожаротушения в общем случае призваны начинать тушение очага возгорания до прибытия пожарных, то есть на ранней стадии его развития. Автоматические установки пожаротушения оснащены специальными ёмкостями, которые заполнены составами, способными эффективно прекратить процесс горения. При этом лучшими считаются комбинированные установки пожаротушения, которые наряду с автоматическим включением допускают и ручной запуск с диспетчерского пульта.</p>\r\n<p style=\"text-align: justify;\">Существующие в настоящее время системы автоматического тушения пожара делят на следующие типы:</p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: justify;\">- водяные установки;</li>\r\n 	<li style=\"text-align: justify;\">- агрегаты тушения пожара пеной;</li>\r\n 	<li style=\"text-align: justify;\">- системы порошкового пожаротушения;</li>\r\n 	<li style=\"text-align: justify;\">- газовые системы пожаротушения.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">Использование систем газового и порошкового пожаротушения усложняется тем, что вещества, используемые при ликвидации возгорания, опасны для здоровья и жизни человека. Поэтому помещение и вход в него должны быть оборудованы специальными звуковыми и визуальными оповещателями, предупреждающими обслуживающий персонал о начале работы системы автоматического пожаротушения. При этом людям должно быть предоставлено время для того, чтобы покинуть помещение.</p>\r\n<p style=\"text-align: justify;\">Каждый объект, в котором предполагается установка технических средств автоматизации пожаротушения, по своему уникален и имеет свои отличительные особенности. Поэтому универсального решения по их установке не существует. В каждом конкретном случае тщательно изучаются особенности объекта, и разрабатывается соответствующий проект, предусматривающий все нюансы выбора, установки и монтажа оборудования.</p>','Монтажные и пусконаладочные работы систем связи','','inherit','closed','closed','','25-revision-v1','','','2019-10-26 18:11:23','2019-10-26 15:11:23','',25,'http://sintegra-nk.ru/2019/10/26/25-revision-v1/',0,'revision','',0),(88,1,'2019-10-26 18:12:01','2019-10-26 15:12:01','<p style=\"text-align: justify;\">Системы автоматического пожаротушения в общем случае призваны начинать тушение очага возгорания до прибытия пожарных, то есть на ранней стадии его развития. Автоматические установки пожаротушения оснащены специальными ёмкостями, которые заполнены составами, способными эффективно прекратить процесс горения. При этом лучшими считаются комбинированные установки пожаротушения, которые наряду с автоматическим включением допускают и ручной запуск с диспетчерского пульта.</p>\r\n<p style=\"text-align: justify;\">Существующие в настоящее время системы автоматического тушения пожара делят на следующие типы:</p>\r\n<p style=\"text-align: justify;\">- водяные установки;</p>\r\n<p style=\"text-align: justify;\">- агрегаты тушения пожара пеной;</p>\r\n<p style=\"text-align: justify;\">- системы порошкового пожаротушения;</p>\r\n<p style=\"text-align: justify;\">- газовые системы пожаротушения.</p>\r\n<p style=\"text-align: justify;\">Использование систем газового и порошкового пожаротушения усложняется тем, что вещества, используемые при ликвидации возгорания, опасны для здоровья и жизни человека. Поэтому помещение и вход в него должны быть оборудованы специальными звуковыми и визуальными оповещателями, предупреждающими обслуживающий персонал о начале работы системы автоматического пожаротушения. При этом людям должно быть предоставлено время для того, чтобы покинуть помещение.</p>\r\n<p style=\"text-align: justify;\">Каждый объект, в котором предполагается установка технических средств автоматизации пожаротушения, по своему уникален и имеет свои отличительные особенности. Поэтому универсального решения по их установке не существует. В каждом конкретном случае тщательно изучаются особенности объекта, и разрабатывается соответствующий проект, предусматривающий все нюансы выбора, установки и монтажа оборудования.</p>','Монтажные и пусконаладочные работы автоматики противопожарных мероприятий','','inherit','closed','closed','','31-revision-v1','','','2019-10-26 18:12:01','2019-10-26 15:12:01','',31,'http://sintegra-nk.ru/2019/10/26/31-revision-v1/',0,'revision','',0),(89,1,'2019-10-26 18:12:14','2019-10-26 15:12:14','<p style=\"text-align: justify;\">Системы автоматического пожаротушения в общем случае призваны начинать тушение очага возгорания до прибытия пожарных, то есть на ранней стадии его развития. Автоматические установки пожаротушения оснащены специальными ёмкостями, которые заполнены составами, способными эффективно прекратить процесс горения. При этом лучшими считаются комбинированные установки пожаротушения, которые наряду с автоматическим включением допускают и ручной запуск с диспетчерского пульта.</p>\r\n<p style=\"text-align: justify;\">Существующие в настоящее время системы автоматического тушения пожара делят на следующие типы:</p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: justify;\">- водяные установки;</li>\r\n 	<li style=\"text-align: justify;\">- агрегаты тушения пожара пеной;</li>\r\n 	<li style=\"text-align: justify;\">- системы порошкового пожаротушения;</li>\r\n 	<li style=\"text-align: justify;\">- газовые системы пожаротушения.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">Использов